# ----------------------------- #
# 2. Helper functions
# ----------------------------- #

create_parent_dir <- function(path) {
  if (!is.null(path) && nzchar(path)) {
    dir.create(dirname(path), recursive = TRUE, showWarnings = FALSE)
  }
}


create_dir <- function(path) {
  if (!is.null(path) && nzchar(path)) {
    dir.create(path, recursive = TRUE, showWarnings = FALSE)
  }
}


path_exists <- function(path) {
  !is.null(path) && nzchar(path) && file.exists(path)
}


read_table_auto <- function(path, sheet = 1) {
  
  if (!path_exists(path)) {
    stop("File does not exist: ", path)
  }
  
  ext <- tolower(tools::file_ext(path))
  
  if (ext %in% c("xlsx", "xls")) {
    readxl::read_xlsx(path, sheet = sheet) %>%
      as.data.frame()
  } else if (ext %in% c("csv", "txt")) {
    readr::read_csv(path, show_col_types = FALSE) %>%
      as.data.frame()
  } else {
    stop("Unsupported file extension: ", ext)
  }
}


load_seurat_object <- function(path) {
  
  if (!path_exists(path)) {
    stop("Input RDS file does not exist: ", path)
  }
  
  obj <- readRDS(path)
  
  if (!inherits(obj, "Seurat")) {
    stop("Input RDS does not contain a Seurat object: ", path)
  }
  
  obj
}


get_assay_data_compat <- function(obj, assay, layer_or_slot) {
  
  tryCatch(
    {
      GetAssayData(obj, assay = assay, layer = layer_or_slot)
    },
    error = function(e) {
      suppressWarnings(
        GetAssayData(obj, assay = assay, slot = layer_or_slot)
      )
    }
  )
}


safe_select_existing <- function(df, cols) {
  df %>% select(any_of(cols))
}


make_clone_key <- function(df, group_col = "sample") {
  
  required <- c(group_col, "TRB_v_gene", "TRB_j_gene", "TRB_cdr3")
  
  if (!all(required %in% colnames(df))) {
    stop(
      "Cannot build clone_key. Missing columns: ",
      paste(setdiff(required, colnames(df)), collapse = ", ")
    )
  }
  
  df %>%
    mutate(
      clone_key = paste(
        .data[[group_col]],
        TRB_v_gene,
        TRB_j_gene,
        TRB_cdr3,
        sep = "|"
      )
    )
}


make_global_clone_key <- function(df) {
  
  required <- c("TRB_v_gene", "TRB_j_gene", "TRB_cdr3")
  
  if (!all(required %in% colnames(df))) {
    stop(
      "Cannot build clone_key_global. Missing columns: ",
      paste(setdiff(required, colnames(df)), collapse = ", ")
    )
  }
  
  df %>%
    mutate(
      clone_key_global = if_else(
        !is.na(TRB_cdr3) & TRB_cdr3 != "" &
          !is.na(TRB_v_gene) & TRB_v_gene != "" &
          !is.na(TRB_j_gene) & TRB_j_gene != "",
        paste(TRB_v_gene, TRB_j_gene, TRB_cdr3, sep = "|"),
        NA_character_
      )
    )
}


normalise_tetramer_name <- function(x) {
  x <- as.character(x)
  x <- ifelse(grepl("^RPPK", x), sub("^RPPK", "RPQK", x), x)
  x
}


# ----------------------------- #
# 3. Collapse VDJ contigs
# ----------------------------- #

collapse_vdj_to_one_row_per_cell <- function(vdj_df, cfg) {
  
  required_cols <- c(
    cfg$barcode_col,
    cfg$chain_col,
    cfg$tcr_columns,
    cfg$umi_col,
    cfg$reads_col
  )
  
  missing_cols <- setdiff(required_cols, colnames(vdj_df))
  
  if (length(missing_cols) > 0) {
    stop("VDJ table is missing required columns: ", paste(missing_cols, collapse = ", "))
  }
  
  meta_columns <- setdiff(
    colnames(vdj_df),
    c(
      cfg$tcr_columns,
      cfg$chain_col,
      cfg$barcode_col,
      "contig_id",
      cfg$umi_col,
      cfg$reads_col,
      "length",
      "productive"
    )
  )
  
  vdj_labeled <- vdj_df %>%
    filter(.data[[cfg$chain_col]] %in% c("TRA", "TRB")) %>%
    mutate(across(all_of(cfg$tcr_columns), as.character)) %>%
    group_by(.data[[cfg$barcode_col]], .data[[cfg$chain_col]]) %>%
    mutate(chain_index = row_number()) %>%
    ungroup() %>%
    mutate(chain_label = paste0(.data[[cfg$chain_col]], chain_index))
  
  vdj_wide <- vdj_labeled %>%
    select(
      all_of(cfg$barcode_col),
      chain_label,
      all_of(cfg$tcr_columns),
      all_of(c(cfg$umi_col, cfg$reads_col))
    ) %>%
    pivot_wider(
      names_from = chain_label,
      values_from = c(all_of(cfg$tcr_columns), all_of(c(cfg$umi_col, cfg$reads_col))),
      names_glue = "{chain_label}_{.value}"
    )
  
  meta_df <- vdj_df %>%
    select(all_of(cfg$barcode_col), all_of(meta_columns)) %>%
    distinct(.data[[cfg$barcode_col]], .keep_all = TRUE)
  
  collapsed <- vdj_wide %>%
    left_join(meta_df, by = cfg$barcode_col)
  
  collapsed
}


save_multi_trb_table <- function(df_collapsed, cfg) {
  
  if (!all(c("TRB1_cdr3", "TRB2_cdr3") %in% colnames(df_collapsed))) {
    multi_trb <- tibble()
  } else {
    multi_trb <- df_collapsed %>%
      filter(!is.na(TRB1_cdr3) & !is.na(TRB2_cdr3))
  }
  
  readr::write_csv(multi_trb, cfg$output_collapsed_multi_trb_csv)
  
  invisible(multi_trb)
}


resolve_double_chain_by_umi <- function(df, chain = "TRB", barcode_col = "barcode") {
  
  chain1_prefix <- paste0(chain, "1_")
  chain2_prefix <- paste0(chain, "2_")
  
  chain1_cdr3 <- paste0(chain, "1_cdr3")
  chain2_cdr3 <- paste0(chain, "2_cdr3")
  chain1_umis <- paste0(chain, "1_umis")
  chain2_umis <- paste0(chain, "2_umis")
  
  if (!all(c(chain1_cdr3, chain2_cdr3, chain1_umis, chain2_umis) %in% colnames(df))) {
    return(list(
      df = df,
      summary = tibble(
        chain = chain,
        n_double_chain_cells = 0L,
        n_dropped_tied_or_missing_umi = 0L,
        n_kept_chain1 = 0L,
        n_moved_chain2_to_chain1 = 0L
      )
    ))
  }
  
  chain1_cols <- grep(paste0("^", chain1_prefix), colnames(df), value = TRUE)
  chain2_cols <- grep(paste0("^", chain2_prefix), colnames(df), value = TRUE)
  
  suffix1 <- sub(paste0("^", chain1_prefix), "", chain1_cols)
  suffix2 <- sub(paste0("^", chain2_prefix), "", chain2_cols)
  shared_suffix <- intersect(suffix1, suffix2)
  
  chain1_shared_cols <- paste0(chain1_prefix, shared_suffix)
  chain2_shared_cols <- paste0(chain2_prefix, shared_suffix)
  
  multi_idx <- !is.na(df[[chain1_cdr3]]) & !is.na(df[[chain2_cdr3]])
  
  drop_idx <- multi_idx & (
    is.na(df[[chain1_umis]]) |
      is.na(df[[chain2_umis]]) |
      df[[chain1_umis]] == df[[chain2_umis]]
  )
  
  keep_chain1_idx <- multi_idx & !drop_idx & df[[chain1_umis]] > df[[chain2_umis]]
  move_chain2_idx <- multi_idx & !drop_idx & df[[chain2_umis]] > df[[chain1_umis]]
  
  if (any(move_chain2_idx)) {
    df[move_chain2_idx, chain1_shared_cols] <- df[move_chain2_idx, chain2_shared_cols]
  }
  
  if (any(multi_idx & !drop_idx)) {
    df[multi_idx & !drop_idx, chain2_shared_cols] <- NA
  }
  
  dropped_barcodes <- df[[barcode_col]][drop_idx]
  
  df <- df %>%
    filter(!.data[[barcode_col]] %in% dropped_barcodes)
  
  summary <- tibble(
    chain = chain,
    n_double_chain_cells = sum(multi_idx, na.rm = TRUE),
    n_dropped_tied_or_missing_umi = length(dropped_barcodes),
    n_kept_chain1 = sum(keep_chain1_idx, na.rm = TRUE),
    n_moved_chain2_to_chain1 = sum(move_chain2_idx, na.rm = TRUE)
  )
  
  list(df = df, summary = summary)
}


collapse_resolved_chain_columns <- function(df) {
  
  # Collapse TRB1/TRB2 into TRB_*.
  df <- df %>%
    mutate(
      TRB_cdr3    = coalesce(TRB1_cdr3,    TRB2_cdr3),
      TRB_v_gene  = coalesce(TRB1_v_gene,  TRB2_v_gene),
      TRB_d_gene  = coalesce(TRB1_d_gene,  TRB2_d_gene),
      TRB_j_gene  = coalesce(TRB1_j_gene,  TRB2_j_gene),
      TRB_c_gene  = coalesce(TRB1_c_gene,  TRB2_c_gene),
      TRB_cdr3_nt = coalesce(TRB1_cdr3_nt, TRB2_cdr3_nt),
      TRB_umis    = coalesce(TRB1_umis,    TRB2_umis),
      TRB_reads   = coalesce(TRB1_reads,   TRB2_reads)
    )
  
  # Collapse TRA1/TRA2 into TRA_*.
  df <- df %>%
    mutate(
      TRA_cdr3    = coalesce(TRA1_cdr3,    TRA2_cdr3),
      TRA_v_gene  = coalesce(TRA1_v_gene,  TRA2_v_gene),
      TRA_d_gene  = coalesce(TRA1_d_gene,  TRA2_d_gene),
      TRA_j_gene  = coalesce(TRA1_j_gene,  TRA2_j_gene),
      TRA_c_gene  = coalesce(TRA1_c_gene,  TRA2_c_gene),
      TRA_cdr3_nt = coalesce(TRA1_cdr3_nt, TRA2_cdr3_nt),
      TRA_umis    = coalesce(TRA1_umis,    TRA2_umis),
      TRA_reads   = coalesce(TRA1_reads,   TRA2_reads)
    ) %>%
    select(
      -starts_with("TRB1_"),
      -starts_with("TRB2_"),
      -starts_with("TRA1_"),
      -starts_with("TRA2_")
    ) %>%
    filter(!is.na(TRB_cdr3), TRB_cdr3 != "")
  
  df
}


prepare_collapsed_tcr_table <- function(vdj_df, cfg) {
  
  message("Collapsing VDJ table to one row per cell...")
  
  df_collapsed <- collapse_vdj_to_one_row_per_cell(vdj_df, cfg)
  
  save_multi_trb_table(df_collapsed, cfg)
  
  trb_resolved <- resolve_double_chain_by_umi(
    df = df_collapsed,
    chain = "TRB",
    barcode_col = cfg$barcode_col
  )
  
  tra_resolved <- resolve_double_chain_by_umi(
    df = trb_resolved$df,
    chain = "TRA",
    barcode_col = cfg$barcode_col
  )
  
  chain_summary <- bind_rows(
    trb_resolved$summary,
    tra_resolved$summary
  )
  
  df_final <- collapse_resolved_chain_columns(tra_resolved$df)
  
  list(
    tcr = df_final,
    summary = chain_summary
  )
}


# ----------------------------- #
# 4. Join Seurat metadata
# ----------------------------- #

ensure_barcode_key_in_metadata <- function(obj, cfg) {
  
  meta <- obj@meta.data
  
  if (cfg$vdj_barcode_key_col %in% colnames(meta)) {
    return(obj)
  }
  
  if (!cfg$id_col %in% colnames(meta)) {
    stop("Cannot create VDJ barcode key because metadata lacks: ", cfg$id_col)
  }
  
  raw_barcode <- sub("^.*_", "", rownames(meta))
  
  obj@meta.data[[cfg$vdj_barcode_key_col]] <- paste0(
    obj@meta.data[[cfg$id_col]],
    "_",
    raw_barcode
  )
  
  obj
}


join_tcr_with_seurat_metadata <- function(tcr_df, obj, cfg) {
  
  obj <- ensure_barcode_key_in_metadata(obj, cfg)
  
  meta <- obj@meta.data %>%
    as.data.frame() %>%
    rownames_to_column("seurat_cell")
  
  needed_meta <- c(
    "seurat_cell",
    cfg$vdj_barcode_key_col,
    cfg$sample_col,
    "age",
    "sex",
    "diagnosis",
    "years_since_diagnosis",
    "cohort",
    cfg$tetramer_col,
    cfg$tetramer_clr_col
  )
  
  meta_to_add <- meta %>%
    select(any_of(needed_meta)) %>%
    distinct(.data[[cfg$vdj_barcode_key_col]], .keep_all = TRUE)
  
  joined <- tcr_df %>%
    left_join(
      meta_to_add,
      by = setNames(cfg$vdj_barcode_key_col, cfg$barcode_col)
    )
  
  if (cfg$sample_col %in% colnames(joined)) {
    joined[[cfg$sample_col]] <- as.character(joined[[cfg$sample_col]])
  }
  
  joined <- joined %>%
    mutate(
      !!cfg$tetramer_col := normalise_tetramer_name(.data[[cfg$tetramer_col]]),
      !!cfg$tetramer_col := if_else(
        is.na(.data[[cfg$tetramer_col]]) | .data[[cfg$tetramer_col]] == "",
        cfg$negative_tetramer_label,
        .data[[cfg$tetramer_col]]
      ),
      !!cfg$tetramer_clr_col := if_else(
        is.na(as.numeric(.data[[cfg$tetramer_clr_col]])),
        0,
        as.numeric(.data[[cfg$tetramer_clr_col]])
      )
    )
  
  joined %>%
    filter(!is.na(.data[[cfg$sample_col]]), .data[[cfg$sample_col]] != "")
}


reorder_tcr_columns <- function(df, cfg) {
  
  preferred_cols <- c(
    cfg$barcode_col,
    cfg$batch_col,
    cfg$id_col,
    "seurat_cell",
    cfg$tetramer_col,
    cfg$tetramer_clr_col,
    "TRA_v_gene",
    "TRA_d_gene",
    "TRA_j_gene",
    "TRA_c_gene",
    "TRA_cdr3",
    "TRA_cdr3_nt",
    "TRB_v_gene",
    "TRB_d_gene",
    "TRB_j_gene",
    "TRB_c_gene",
    "TRB_cdr3",
    "TRB_cdr3_nt",
    cfg$sample_col,
    "cohort",
    "diagnosis",
    "age",
    "sex",
    "years_since_diagnosis"
  )
  
  df %>%
    select(any_of(preferred_cols), everything())
}


# ----------------------------- #
# 5. Within-sample QC
# ----------------------------- #

make_within_sample_conflict_tables <- function(df, cfg) {
  
  df2 <- df %>%
    filter(
      !is.na(TRB_cdr3), TRB_cdr3 != "",
      !is.na(TRB_v_gene), TRB_v_gene != "",
      !is.na(TRB_j_gene), TRB_j_gene != "",
      !is.na(.data[[cfg$tetramer_col]]), .data[[cfg$tetramer_col]] != ""
    ) %>%
    make_clone_key(group_col = cfg$sample_col)
  
  conflict_keys <- df2 %>%
    group_by(clone_key) %>%
    summarise(n_tetramers = n_distinct(.data[[cfg$tetramer_col]]), .groups = "drop") %>%
    filter(n_tetramers > 1) %>%
    pull(clone_key)
  
  df_conflict <- df2 %>%
    filter(clone_key %in% conflict_keys)
  
  if (nrow(df_conflict) == 0) {
    empty_summary <- tibble()
    empty_auto <- tibble()
    return(list(
      df_with_key = df2,
      conflict_cells = df_conflict,
      conflict_summary = empty_summary,
      auto_calls = empty_auto
    ))
  }
  
  tet_counts <- df_conflict %>%
    count(clone_key, tetramer = .data[[cfg$tetramer_col]], name = "n_cells") %>%
    group_by(clone_key) %>%
    summarise(
      tetramer_counts = paste0(tetramer, "=", n_cells, collapse = "; "),
      .groups = "drop"
    )
  
  id_counts <- df_conflict %>%
    count(clone_key, id = .data[[cfg$id_col]], name = "n_cells") %>%
    group_by(clone_key) %>%
    summarise(
      id_counts = paste0(id, "=", n_cells, collapse = "; "),
      .groups = "drop"
    )
  
  tet_by_id <- df_conflict %>%
    count(clone_key, id = .data[[cfg$id_col]], tetramer = .data[[cfg$tetramer_col]], name = "n_cells") %>%
    arrange(clone_key, id, desc(n_cells)) %>%
    group_by(clone_key, id) %>%
    summarise(
      tet_counts_in_id = paste0(tetramer, "=", n_cells, collapse = ", "),
      .groups = "drop"
    ) %>%
    group_by(clone_key) %>%
    summarise(
      tetramer_by_id = paste0(id, ": ", tet_counts_in_id, collapse = " | "),
      .groups = "drop"
    )
  
  conflict_summary <- df_conflict %>%
    group_by(clone_key) %>%
    summarise(
      sample = first(.data[[cfg$sample_col]]),
      TRB_v_gene = first(TRB_v_gene),
      TRB_j_gene = first(TRB_j_gene),
      TRB_cdr3 = first(TRB_cdr3),
      n_cells_total = n(),
      n_tetramers = n_distinct(.data[[cfg$tetramer_col]]),
      .groups = "drop"
    ) %>%
    left_join(tet_counts, by = "clone_key") %>%
    left_join(id_counts, by = "clone_key") %>%
    left_join(tet_by_id, by = "clone_key") %>%
    arrange(desc(n_cells_total), desc(n_tetramers))
  
  clone_stats <- df_conflict %>%
    count(clone_key, tet = .data[[cfg$tetramer_col]], name = "n") %>%
    group_by(clone_key) %>%
    summarise(
      tetramer_counts = paste0(tet, "=", n, collapse = "; "),
      n_neg = sum(n[tet == cfg$negative_tetramer_label], na.rm = TRUE),
      top_nonneg_n = ifelse(
        any(tet != cfg$negative_tetramer_label),
        max(n[tet != cfg$negative_tetramer_label], na.rm = TRUE),
        NA_integer_
      ),
      top_nonneg_tets = ifelse(
        any(tet != cfg$negative_tetramer_label),
        paste(
          tet[
            tet != cfg$negative_tetramer_label &
              n == max(n[tet != cfg$negative_tetramer_label], na.rm = TRUE)
          ],
          collapse = "|"
        ),
        NA_character_
      ),
      n_top_nonneg_tets = ifelse(
        any(tet != cfg$negative_tetramer_label),
        sum(
          tet != cfg$negative_tetramer_label &
            n == max(n[tet != cfg$negative_tetramer_label], na.rm = TRUE)
        ),
        NA_integer_
      ),
      second_nonneg_n = {
        nn <- n[tet != cfg$negative_tetramer_label]
        if (length(nn) >= 2) sort(nn, decreasing = TRUE)[2] else 0
      },
      .groups = "drop"
    ) %>%
    mutate(
      neg_ties_top_nonneg = !is.na(top_nonneg_n) &
        n_neg == top_nonneg_n &
        top_nonneg_n > 0,
      
      tetramer_auto = case_when(
        !is.na(top_nonneg_n) & n_neg > top_nonneg_n ~ cfg$negative_tetramer_label,
        is.na(top_nonneg_n) & n_neg > 0 ~ cfg$negative_tetramer_label,
        neg_ties_top_nonneg ~ NA_character_,
        !is.na(top_nonneg_n) &
          n_top_nonneg_tets == 1 &
          top_nonneg_n > n_neg &
          top_nonneg_n > second_nonneg_n ~ str_split_i(top_nonneg_tets, "\\|", 1),
        !is.na(top_nonneg_n) & n_top_nonneg_tets > 1 ~ NA_character_,
        TRUE ~ cfg$negative_tetramer_label
      ),
      
      needs_vdjdb = neg_ties_top_nonneg |
        (!is.na(top_nonneg_n) & n_top_nonneg_tets > 1),
      
      rule_used = case_when(
        !is.na(top_nonneg_n) & n_neg > top_nonneg_n ~ "negatives_dominate",
        is.na(top_nonneg_n) & n_neg > 0 ~ "negatives_only",
        neg_ties_top_nonneg ~ "neg_vs_nonneg_tie_needs_vdjdb",
        !is.na(top_nonneg_n) &
          n_top_nonneg_tets == 1 &
          top_nonneg_n > n_neg &
          top_nonneg_n > second_nonneg_n ~ "majority_nonneg",
        !is.na(top_nonneg_n) & n_top_nonneg_tets > 1 ~ "tie_needs_vdjdb",
        TRUE ~ "fallback_negative"
      )
    )
  
  conflict_summary_auto <- conflict_summary %>%
    left_join(
      clone_stats %>%
        select(clone_key, tetramer_auto, needs_vdjdb, rule_used),
      by = "clone_key"
    ) %>%
    arrange(desc(n_cells_total), desc(n_tetramers))
  
  list(
    df_with_key = df2,
    conflict_cells = df_conflict,
    conflict_summary = conflict_summary,
    auto_calls = conflict_summary_auto
  )
}


load_within_manual_map <- function(path, cfg) {
  
  if (!path_exists(path)) {
    return(tibble(
      clone_key = character(),
      tetramer_final = character(),
      qc1_source = character()
    ))
  }
  
  message("Loading within-sample manual VDJdb calls: ", path)
  
  conf <- read_table_auto(path)
  
  if (!"clone_key" %in% colnames(conf)) {
    needed <- c(cfg$sample_col, "TRB_v_gene", "TRB_j_gene", "TRB_cdr3")
    
    if (!all(needed %in% colnames(conf))) {
      stop(
        "Manual within-sample file needs either clone_key or columns: ",
        paste(needed, collapse = ", ")
      )
    }
    
    conf <- make_clone_key(conf, group_col = cfg$sample_col)
  }
  
  if (!cfg$manual_within_tetramer_col %in% colnames(conf)) {
    stop(
      "Manual within-sample file does not contain tetramer column: ",
      cfg$manual_within_tetramer_col
    )
  }
  
  conf_map <- conf %>%
    filter(
      !is.na(.data[[cfg$manual_within_tetramer_col]]),
      .data[[cfg$manual_within_tetramer_col]] != ""
    ) %>%
    transmute(
      clone_key = as.character(clone_key),
      tetramer_final = as.character(.data[[cfg$manual_within_tetramer_col]]),
      qc1_source = "manual_vdjdb_within_sample"
    ) %>%
    distinct(clone_key, .keep_all = TRUE)
  
  duplicated_keys <- conf_map %>%
    count(clone_key) %>%
    filter(n > 1)
  
  if (nrow(duplicated_keys) > 0) {
    stop("Manual within-sample file contains duplicated clone_key values.")
  }
  
  conf_map
}


apply_within_sample_qc <- function(df, conflict_result, cfg) {
  
  df_full <- df %>%
    make_clone_key(group_col = cfg$sample_col)
  
  manual_map <- load_within_manual_map(
    path = cfg$manual_within_sample_file,
    cfg = cfg
  )
  
  auto_map <- conflict_result$auto_calls %>%
    filter(!is.na(tetramer_auto)) %>%
    transmute(
      clone_key = as.character(clone_key),
      tetramer_final = as.character(tetramer_auto),
      qc1_source = paste0("auto_", rule_used)
    )
  
  if (nrow(manual_map) > 0) {
    qc1_map <- bind_rows(
      manual_map,
      auto_map %>% filter(!clone_key %in% manual_map$clone_key)
    )
  } else if (isTRUE(cfg$use_auto_qc_when_manual_missing)) {
    qc1_map <- auto_map
  } else {
    qc1_map <- tibble(
      clone_key = character(),
      tetramer_final = character(),
      qc1_source = character()
    )
  }
  
  df_full %>%
    left_join(qc1_map, by = "clone_key") %>%
    mutate(
      tetramer_final_call = if_else(
        !is.na(tetramer_final),
        tetramer_final,
        .data[[cfg$tetramer_col]]
      ),
      tetramer_final_call = if_else(
        is.na(tetramer_final_call) | tetramer_final_call == "",
        cfg$negative_tetramer_label,
        tetramer_final_call
      ),
      tetramer_was_overridden = !is.na(tetramer_final),
      qc1_source = if_else(is.na(qc1_source), "unchanged", qc1_source)
    )
}


# ----------------------------- #
# 6. Global QC
# ----------------------------- #

make_global_conflict_tables <- function(df, cfg) {
  
  df_qc2 <- df %>%
    mutate(
      tetramer = tetramer_final_call,
      tetramer = if_else(is.na(tetramer) | tetramer == "", cfg$negative_tetramer_label, tetramer)
    ) %>%
    filter(
      !is.na(TRB_cdr3), TRB_cdr3 != "",
      !is.na(TRB_v_gene), TRB_v_gene != "",
      !is.na(TRB_j_gene), TRB_j_gene != "",
      !is.na(tetramer), tetramer != ""
    ) %>%
    make_global_clone_key()
  
  conflict_keys <- df_qc2 %>%
    group_by(clone_key_global) %>%
    summarise(n_tetramers = n_distinct(tetramer), .groups = "drop") %>%
    filter(n_tetramers > 1) %>%
    pull(clone_key_global)
  
  df_global_conflict <- df_qc2 %>%
    filter(clone_key_global %in% conflict_keys)
  
  if (nrow(df_global_conflict) == 0) {
    return(list(
      df_qc2 = df_qc2,
      conflict_summary = tibble(),
      qc2_calls = tibble()
    ))
  }
  
  tet_counts_global <- df_global_conflict %>%
    count(clone_key_global, tetramer, name = "n_cells") %>%
    group_by(clone_key_global) %>%
    summarise(
      tetramer_counts = paste0(tetramer, "=", n_cells, collapse = "; "),
      .groups = "drop"
    )
  
  sample_counts_global <- df_global_conflict %>%
    count(clone_key_global, sample, name = "n_cells") %>%
    group_by(clone_key_global) %>%
    summarise(
      sample_counts = paste0(sample, "=", n_cells, collapse = "; "),
      .groups = "drop"
    )
  
  tet_by_sample <- df_global_conflict %>%
    count(clone_key_global, sample, tetramer, name = "n_cells") %>%
    arrange(clone_key_global, sample, desc(n_cells)) %>%
    group_by(clone_key_global, sample) %>%
    summarise(
      tet_counts_in_sample = paste0(tetramer, "=", n_cells, collapse = ", "),
      .groups = "drop"
    ) %>%
    group_by(clone_key_global) %>%
    summarise(
      tetramer_by_sample = paste0(sample, ": ", tet_counts_in_sample, collapse = " | "),
      .groups = "drop"
    )
  
  conflict_summary <- df_global_conflict %>%
    group_by(clone_key_global) %>%
    summarise(
      TRB_v_gene = first(TRB_v_gene),
      TRB_j_gene = first(TRB_j_gene),
      TRB_cdr3 = first(TRB_cdr3),
      n_cells_total = n(),
      n_tetramers = n_distinct(tetramer),
      n_samples = n_distinct(sample),
      .groups = "drop"
    ) %>%
    left_join(tet_counts_global, by = "clone_key_global") %>%
    left_join(sample_counts_global, by = "clone_key_global") %>%
    left_join(tet_by_sample, by = "clone_key_global") %>%
    arrange(desc(n_cells_total), desc(n_samples), desc(n_tetramers))
  
  qc2_calls <- df_global_conflict %>%
    count(clone_key_global, tetramer, name = "n_cells") %>%
    group_by(clone_key_global) %>%
    summarise(
      tetramer_counts = paste0(tetramer, "=", n_cells, collapse = "; "),
      top_n = max(n_cells),
      n_top = sum(n_cells == max(n_cells)),
      top_tets = paste(tetramer[n_cells == max(n_cells)], collapse = "|"),
      tetramer_qc2 = ifelse(n_top == 1, str_split_i(top_tets, "\\|", 1), NA_character_),
      qc2_needs_vdjdb = n_top > 1,
      qc2_rule = ifelse(n_top == 1, "qc2_highest_unique", "qc2_tie_needs_vdjdb"),
      .groups = "drop"
    )
  
  list(
    df_qc2 = df_qc2,
    conflict_summary = conflict_summary,
    qc2_calls = qc2_calls
  )
}


load_global_manual_map <- function(path, cfg) {
  
  if (!path_exists(path)) {
    return(tibble(
      clone_key_global = character(),
      new_tetramer = character(),
      qc2_source = character()
    ))
  }
  
  message("Loading global manual VDJdb calls: ", path)
  
  global_map_raw <- read_table_auto(path)
  
  if (!"clone_key_global" %in% colnames(global_map_raw)) {
    needed <- c("TRB_v_gene", "TRB_j_gene", "TRB_cdr3")
    
    if (!all(needed %in% colnames(global_map_raw))) {
      stop(
        "Manual global file needs either clone_key_global or columns: ",
        paste(needed, collapse = ", ")
      )
    }
    
    global_map_raw <- make_global_clone_key(global_map_raw)
  }
  
  if (!cfg$manual_global_tetramer_col %in% colnames(global_map_raw)) {
    stop(
      "Manual global file does not contain tetramer column: ",
      cfg$manual_global_tetramer_col
    )
  }
  
  global_map <- global_map_raw %>%
    filter(
      !is.na(.data[[cfg$manual_global_tetramer_col]]),
      .data[[cfg$manual_global_tetramer_col]] != ""
    ) %>%
