apply_global_qc <- function(df_qc1, global_result, cfg) {
  
  df_final2 <- df_qc1 %>%
    mutate(
      tetramer = tetramer_final_call,
      tetramer = if_else(is.na(tetramer) | tetramer == "", cfg$negative_tetramer_label, tetramer)
    ) %>%
    make_global_clone_key()
  
  manual_map <- load_global_manual_map(
    path = cfg$manual_global_file,
    cfg = cfg
  )
  
  auto_map <- global_result$qc2_calls %>%
    filter(!is.na(tetramer_qc2)) %>%
    transmute(
      clone_key_global = as.character(clone_key_global),
      new_tetramer = as.character(tetramer_qc2),
      qc2_source = qc2_rule
    )
  
  if (nrow(manual_map) > 0) {
    qc2_map <- bind_rows(
      manual_map,
      auto_map %>% filter(!clone_key_global %in% manual_map$clone_key_global)
    )
  } else if (isTRUE(cfg$use_auto_qc_when_manual_missing)) {
    qc2_map <- auto_map
  } else {
    qc2_map <- tibble(
      clone_key_global = character(),
      new_tetramer = character(),
      qc2_source = character()
    )
  }
  
  df_final2 %>%
    left_join(qc2_map, by = "clone_key_global") %>%
    mutate(
      tetramer_qc2_final = if_else(!is.na(new_tetramer), new_tetramer, tetramer),
      tetramer_qc2_final = if_else(
        is.na(tetramer_qc2_final) | tetramer_qc2_final == "",
        cfg$negative_tetramer_label,
        tetramer_qc2_final
      ),
      qc2_was_overridden = !is.na(new_tetramer),
      qc2_source = if_else(is.na(qc2_source), "unchanged", qc2_source)
    )
}


# ----------------------------- #
# 7. HLA mismatch filtering
# ----------------------------- #

apply_hla_filter <- function(df, cfg) {
  
  if (!path_exists(cfg$tetramer_hla_file) || !path_exists(cfg$hla_info_file)) {
    message("Skipping HLA filtering because HLA reference files are missing.")
    
    return(list(
      df_filtered = df,
      bad_calls = tibble()
    ))
  }
  
  message("Applying HLA mismatch filter...")
  
  tetramer_hla <- readxl::read_xlsx(cfg$tetramer_hla_file) %>%
    as.data.frame()
  
  hla <- readxl::read_xlsx(cfg$hla_info_file) %>%
    as.data.frame()
  
  if (!"tetramer" %in% colnames(tetramer_hla)) {
    stop("Tetramer HLA file must contain a 'tetramer' column.")
  }
  
  if (!cfg$sample_col %in% colnames(hla)) {
    stop("HLA information file must contain a sample column: ", cfg$sample_col)
  }
  
  tetramer_long <- tetramer_hla %>%
    pivot_longer(
      cols = -tetramer,
      names_to = "allele",
      values_to = "tetramer_hla_status"
    ) %>%
    filter(tetramer_hla_status == "positive") %>%
    transmute(
      tetramer = as.character(tetramer),
      allele = as.character(allele)
    ) %>%
    distinct()
  
  hla_long <- hla %>%
    pivot_longer(
      cols = -all_of(cfg$sample_col),
      names_to = "allele",
      values_to = "sample_hla_status"
    ) %>%
    filter(sample_hla_status == "positive") %>%
    transmute(
      sample = as.character(.data[[cfg$sample_col]]),
      allele = as.character(allele)
    ) %>%
    distinct()
  
  valid_pairs <- tetramer_long %>%
    inner_join(hla_long, by = "allele") %>%
    distinct(tetramer, sample)
  
  known_tetramers <- unique(valid_pairs$tetramer)
  known_samples <- unique(valid_pairs$sample)
  
  df2 <- df %>%
    mutate(
      tetramer_raw_final = tetramer_qc2_final,
      tetramer_key = str_replace(str_trim(tetramer_qc2_final), "\\*$", "")
    )
  
  bad_calls <- df2 %>%
    filter(
      !is.na(tetramer_key),
      tetramer_key != cfg$negative_tetramer_label,
      tetramer_key %in% known_tetramers,
      .data[[cfg$sample_col]] %in% known_samples
    ) %>%
    anti_join(
      valid_pairs,
      by = c("tetramer_key" = "tetramer", "sample" = "sample")
    )
  
  df_filtered <- df2 %>%
    anti_join(
      bad_calls %>%
        select(all_of(cfg$barcode_col)) %>%
        distinct(),
      by = cfg$barcode_col
    )
  
  list(
    df_filtered = df_filtered,
    bad_calls = bad_calls
  )
}


# ----------------------------- #
# 8. Project GEM tetramer calls onto non-GEM cells
# ----------------------------- #

project_gem_tetramers_to_non_gem <- function(df_gem_qc, df_non_gem, cfg) {
  
  gem_tet_col <- "tetramer_qc2_final"
  
  df_gem <- df_gem_qc %>%
    filter(
      !is.na(.data[[cfg$sample_col]]), .data[[cfg$sample_col]] != "",
      !is.na(TRB_v_gene), TRB_v_gene != "",
      !is.na(TRB_j_gene), TRB_j_gene != "",
      !is.na(TRB_cdr3), TRB_cdr3 != "",
      !is.na(.data[[gem_tet_col]]), .data[[gem_tet_col]] != ""
    ) %>%
    mutate(
      clone_key = paste(.data[[cfg$sample_col]], TRB_v_gene, TRB_j_gene, TRB_cdr3, sep = "|")
    )
  
  df_non <- df_non_gem %>%
    filter(
      !is.na(.data[[cfg$sample_col]]), .data[[cfg$sample_col]] != "",
      !is.na(TRB_v_gene), TRB_v_gene != "",
      !is.na(TRB_j_gene), TRB_j_gene != "",
      !is.na(TRB_cdr3), TRB_cdr3 != ""
    ) %>%
    mutate(
      clone_key = paste(.data[[cfg$sample_col]], TRB_v_gene, TRB_j_gene, TRB_cdr3, sep = "|")
    )
  
  gem_map_check <- df_gem %>%
    group_by(.data[[cfg$sample_col]], clone_key) %>%
    summarise(n_tet = n_distinct(.data[[gem_tet_col]]), .groups = "drop") %>%
    filter(n_tet > 1)
  
  if (nrow(gem_map_check) > 0) {
    print(head(gem_map_check, 50))
    stop("Baseline GEM still has >1 tetramer call for some sample-level clones.")
  }
  
  gem_clone_map <- df_gem %>%
    distinct(
      .data[[cfg$sample_col]],
      clone_key,
      .data[[gem_tet_col]]
    ) %>%
    rename(tetramer_from_GEM = !!gem_tet_col)
  
  df_non_projected <- df_non %>%
    left_join(
      gem_clone_map,
      by = c(cfg$sample_col, "clone_key")
    ) %>%
    mutate(
      tetramer = case_when(
        !is.na(tetramer_from_GEM) ~ tetramer_from_GEM,
        str_detect(.data[[cfg$batch_col]], cfg$dex_batch_regex) ~ cfg$enriched_label,
        str_detect(.data[[cfg$batch_col]], cfg$cd8_batch_regex) ~ cfg$lcl_responsive_label,
        TRUE ~ cfg$negative_tetramer_label
      ),
      tetramer_source = case_when(
        !is.na(tetramer_from_GEM) ~ "projected_from_GEM_same_sample",
        str_detect(.data[[cfg$batch_col]], cfg$dex_batch_regex) ~ "batch_inferred",
        str_detect(.data[[cfg$batch_col]], cfg$cd8_batch_regex) ~ "batch_inferred",
        TRUE ~ "negative"
      ),
      data_source = "nonGEM_activated"
    ) %>%
    select(-tetramer_from_GEM)
  
  df_gem_final <- df_gem_qc %>%
    mutate(
      tetramer = tetramer_qc2_final,
      tetramer = if_else(is.na(tetramer) | tetramer == "", cfg$negative_tetramer_label, tetramer),
      data_source = "GEM_baseline",
      tetramer_source = "GEM_measured_QC1_QC2_HLA"
    )
  
  bind_rows(df_gem_final, df_non_projected)
}


# ----------------------------- #
# 9. Add VDJ metadata back to Seurat object
# ----------------------------- #

add_vdj_metadata_to_seurat <- function(obj, df_all, cfg) {
  
  obj <- ensure_barcode_key_in_metadata(obj, cfg)
  
  meta <- obj@meta.data %>%
    as.data.frame() %>%
    rownames_to_column("seurat_cell") %>%
    mutate(
      key = as.character(.data[[cfg$vdj_barcode_key_col]])
    )
  
  vdj_to_add <- df_all %>%
    transmute(
      key = as.character(.data[[cfg$barcode_col]]),
      tetramer = as.character(tetramer),
      data_source = as.character(data_source),
      tetramer_source = as.character(tetramer_source),
      TRA_v_gene,
      TRA_d_gene,
      TRA_j_gene,
      TRA_c_gene,
      TRA_cdr3,
      TRA_cdr3_nt,
      TRB_v_gene,
      TRB_d_gene,
      TRB_j_gene,
      TRB_c_gene,
      TRB_cdr3,
      TRB_cdr3_nt
    ) %>%
    distinct(key, .keep_all = TRUE)
  
  meta_matched <- meta %>%
    inner_join(vdj_to_add %>% select(key), by = "key")
  
  cells_keep <- intersect(meta_matched$seurat_cell, colnames(obj))
  
  obj_vdj <- subset(obj, cells = cells_keep)
  
  vdj_meta_for_seurat <- meta_matched %>%
    select(seurat_cell, key) %>%
    left_join(vdj_to_add, by = "key") %>%
    select(-key) %>%
    distinct(seurat_cell, .keep_all = TRUE) %>%
    column_to_rownames("seurat_cell")
  
  vdj_meta_for_seurat <- vdj_meta_for_seurat[colnames(obj_vdj), , drop = FALSE]
  
  AddMetaData(
    object = obj_vdj,
    metadata = vdj_meta_for_seurat
  )
}


# ----------------------------- #
# 10. Virus/antigen annotation
# ----------------------------- #

add_multimer_information <- function(obj, cfg) {
  
  if (!path_exists(cfg$ebv_multimer_info_file)) {
    stop("EBV multimer information file does not exist: ", cfg$ebv_multimer_info_file)
  }
  
  multimer_info <- readxl::read_xlsx(cfg$ebv_multimer_info_file) %>%
    as.data.frame()
  
  required_cols <- c("tetramer", "virus", "lifecycle", "latency", "antigen")
  
  if (!all(required_cols %in% colnames(multimer_info))) {
    stop(
      "EBV multimer information file is missing columns: ",
      paste(setdiff(required_cols, colnames(multimer_info)), collapse = ", ")
    )
  }
  
  multimer_info <- multimer_info %>%
    add_row(
      tetramer = cfg$enriched_label,
      virus = cfg$enriched_label,
      lifecycle = cfg$enriched_label,
      latency = cfg$enriched_label,
      antigen = cfg$enriched_label
    ) %>%
    add_row(
      tetramer = cfg$lcl_responsive_label,
      virus = cfg$lcl_responsive_label,
      lifecycle = cfg$lcl_responsive_label,
      latency = cfg$lcl_responsive_label,
      antigen = cfg$lcl_responsive_label
    ) %>%
    add_row(
      tetramer = cfg$negative_tetramer_label,
      virus = cfg$negative_tetramer_label,
      lifecycle = cfg$negative_tetramer_label,
      latency = cfg$negative_tetramer_label,
      antigen = cfg$negative_tetramer_label
    ) %>%
    distinct(tetramer, .keep_all = TRUE)
  
  meta <- obj@meta.data %>%
    as.data.frame() %>%
    rownames_to_column("cell_barcode")
  
  # Remove old annotation columns before joining.
  meta <- meta %>%
    select(-any_of(c("virus", "lifecycle", "latency", "antigen")))
  
  meta2 <- meta %>%
    left_join(
      multimer_info %>%
        select(tetramer, virus, lifecycle, latency, antigen),
      by = "tetramer"
    )
  
  # CD19.1 is treated as negative.
  is_cd19 <- !is.na(meta2$tetramer) & meta2$tetramer == "CD19.1"
  
  meta2$tetramer[is_cd19] <- cfg$negative_tetramer_label
  meta2$virus[is_cd19] <- cfg$negative_tetramer_label
  meta2$lifecycle[is_cd19] <- cfg$negative_tetramer_label
  meta2$latency[is_cd19] <- cfg$negative_tetramer_label
  meta2$antigen[is_cd19] <- cfg$negative_tetramer_label
  
  # For GEMEBV/DEX cells, negative/NA annotations are considered enriched.
  is_gemebv_or_dex <- str_detect(meta2[[cfg$batch_col]], "GEMEBV|DEX")
  
  # For CD8 activated batches, negative/NA annotations are LCL-responsive.
  is_cd8_batch <- str_detect(meta2[[cfg$batch_col]], "CD8")
  
  meta2 <- meta2 %>%
    mutate(
      tetramer = case_when(
        tetramer == cfg$negative_tetramer_label & is_gemebv_or_dex ~ cfg$enriched_label,
        tetramer == cfg$negative_tetramer_label & is_cd8_batch ~ cfg$lcl_responsive_label,
        TRUE ~ tetramer
      ),
      virus = case_when(
        (is.na(virus) | virus == cfg$negative_tetramer_label) & is_gemebv_or_dex ~ cfg$enriched_label,
        (is.na(virus) | virus == cfg$negative_tetramer_label) & is_cd8_batch ~ cfg$lcl_responsive_label,
        TRUE ~ virus
      ),
      lifecycle = case_when(
        (is.na(lifecycle) | lifecycle == cfg$negative_tetramer_label) & is_gemebv_or_dex ~ cfg$enriched_label,
        (is.na(lifecycle) | lifecycle == cfg$negative_tetramer_label) & is_cd8_batch ~ cfg$lcl_responsive_label,
        TRUE ~ lifecycle
      ),
      latency = case_when(
        (is.na(latency) | latency == cfg$negative_tetramer_label) & is_gemebv_or_dex ~ cfg$enriched_label,
        (is.na(latency) | latency == cfg$negative_tetramer_label) & is_cd8_batch ~ cfg$lcl_responsive_label,
        TRUE ~ latency
      ),
      antigen = case_when(
        (is.na(antigen) | antigen == cfg$negative_tetramer_label) & is_gemebv_or_dex ~ cfg$enriched_label,
        (is.na(antigen) | antigen == cfg$negative_tetramer_label) & is_cd8_batch ~ cfg$lcl_responsive_label,
        TRUE ~ antigen
      )
    ) %>%
    column_to_rownames("cell_barcode")
  
  obj@meta.data <- meta2
  
  obj
}


cleanup_metadata <- function(obj, cfg) {
  
  obj@meta.data <- obj@meta.data %>%
    select(-any_of(cfg$metadata_cols_to_remove))
  
  obj
}


# ----------------------------- #
# 11. ADT CD8 gating and final subsets
# ----------------------------- #

add_adt_marker_metadata <- function(obj, cfg) {
  
  if (!cfg$adt_assay %in% Assays(obj)) {
    stop("ADT assay not found in object: ", cfg$adt_assay)
  }
  
  adt_features <- rownames(obj[[cfg$adt_assay]])
  missing_features <- setdiff(cfg$adt_marker_features, adt_features)
  
  if (length(missing_features) > 0) {
    stop(
      "Missing ADT marker features required for gating: ",
      paste(missing_features, collapse = ", ")
    )
  }
  
  adt_mat <- get_assay_data_compat(
    obj = obj,
    assay = cfg$adt_assay,
    layer_or_slot = "data"
  )[cfg$adt_marker_features, , drop = FALSE]
  
  adt_df <- t(as.matrix(adt_mat)) %>%
    as.data.frame()
  
  colnames(adt_df) <- cfg$adt_marker_output_cols
  
  AddMetaData(obj, adt_df)
}


gate_final_cd8_object <- function(obj, cfg) {
  
  meta <- obj@meta.data
  
  required_cols <- c(
    cfg$batch_col,
    "ADT_CD3_norm",
    "ADT_CD4.1_norm",
    "ADT_CD8_norm"
  )
  
  missing_cols <- setdiff(required_cols, colnames(meta))
  
  if (length(missing_cols) > 0) {
    stop("Cannot gate CD8 object. Missing columns: ", paste(missing_cols, collapse = ", "))
  }
  
  is_gemebv_or_ebvlcl <- grepl(cfg$ebv_baseline_batch_regex, meta[[cfg$batch_col]]) |
    grepl(cfg$ebv_activated_batch_regex, meta[[cfg$batch_col]])
  
  is_other_cd8_gated <- !is_gemebv_or_ebvlcl &
    meta$ADT_CD3_norm > cfg$global_cd3_min &
    meta$ADT_CD4.1_norm < cfg$global_cd4_max &
    meta$ADT_CD8_norm > cfg$global_cd8_min
  
  keep_cells <- rownames(meta)[is_gemebv_or_ebvlcl | is_other_cd8_gated]
  
  gated <- subset(obj, cells = keep_cells)
  
  gated <- subset(
    gated,
    subset = !grepl(cd4_batch_regex, batch)
  )
  
  gated
}


make_publication_subsets <- function(obj, cfg) {
  
  baseline <- subset(
    obj,
    subset = grepl(gem_batch_regex, batch)
  )
  
  meta <- obj@meta.data
  
  ebvlcl_samples <- unique(meta[[cfg$sample_col]][grepl(cfg$ebv_activated_batch_regex, meta[[cfg$batch_col]])])
  gem_like_samples <- unique(meta[[cfg$sample_col]][grepl(cfg$gem_batch_regex, meta[[cfg$batch_col]])])
  
  shared_samples <- intersect(ebvlcl_samples, gem_like_samples)
  
  activated_counterpart <- subset(
    obj,
    subset = sample %in% shared_samples
  )
  
  list(
    combined = obj,
    baseline = baseline,
    activated_counterpart = activated_counterpart,
    shared_samples = shared_samples
  )
}


