create_dir(config$output_publication_rds_dir)

output_paths <- unlist(config[grepl("^output_|session_info_file", names(config))])

for (path in output_paths) {
  if (is.character(path) && length(path) == 1 && nzchar(path)) {
    create_parent_dir(path)
  }
}

message("Loading EBV-only VDJ CSV...")
vdj_df <- readr::read_csv(config$input_ebv_vdj_csv, show_col_types = FALSE)

message("Loading EBV CD8 Seurat object...")
merged_ebv_cd8 <- load_seurat_object(config$input_ebv_cd8_rds)

merged_ebv_cd8 <- ensure_barcode_key_in_metadata(merged_ebv_cd8, config)

message("Preparing collapsed TCR table...")
collapsed_result <- prepare_collapsed_tcr_table(vdj_df, config)

tcr_collapsed <- collapsed_result$tcr
chain_resolution_summary <- collapsed_result$summary

readr::write_csv(
  chain_resolution_summary,
  config$output_chain_resolution_summary_csv
)

message("Joining Seurat metadata onto TCR table...")
tcr_with_meta <- join_tcr_with_seurat_metadata(
  tcr_df = tcr_collapsed,
  obj = merged_ebv_cd8,
  cfg = config
) %>%
  reorder_tcr_columns(config)

# Split baseline GEM/GEMEBV from activated/non-GEM.
df_gem <- tcr_with_meta %>%
  filter(grepl(config$gem_batch_regex, .data[[config$batch_col]]))

df_non_gem <- tcr_with_meta %>%
  filter(!grepl(config$gem_batch_regex, .data[[config$batch_col]]))

readr::write_csv(df_gem, config$output_gem_tcr_csv)

message("Running within-sample multimer QC...")
within_result <- make_within_sample_conflict_tables(df_gem, config)

readr::write_csv(
  within_result$conflict_summary,
  config$output_within_conflicts_csv
)

readr::write_csv(
  within_result$auto_calls,
  config$output_within_conflicts_auto_csv
)

df_qc1 <- apply_within_sample_qc(
  df = df_gem,
  conflict_result = within_result,
  cfg = config
)

readr::write_csv(df_qc1, config$output_qc1_csv)

message("Running global/public-clone multimer QC...")
global_result <- make_global_conflict_tables(df_qc1, config)

readr::write_csv(
  global_result$conflict_summary,
  config$output_global_conflicts_csv
)

readr::write_csv(
  global_result$qc2_calls,
  config$output_global_auto_calls_csv
)

df_qc2 <- apply_global_qc(
  df_qc1 = df_qc1,
  global_result = global_result,
  cfg = config
)

readr::write_csv(df_qc2, config$output_qc2_csv)

message("Applying HLA mismatch filtering...")
hla_result <- apply_hla_filter(df_qc2, config)

df_hla_filtered <- hla_result$df_filtered
bad_hla_calls <- hla_result$bad_calls

readr::write_csv(bad_hla_calls, config$output_hla_removed_csv)
readr::write_csv(df_hla_filtered, config$output_hla_filtered_csv)

message("Projecting GEM tetramer calls onto activated/non-GEM TCRs...")
df_all <- project_gem_tetramers_to_non_gem(
  df_gem_qc = df_hla_filtered,
  df_non_gem = df_non_gem,
  cfg = config
)

readr::write_csv(df_all, config$output_projected_tcr_csv)

message("Adding final VDJ/tetramer metadata back to Seurat...")
merged_ebv_cd8_vdj <- add_vdj_metadata_to_seurat(
  obj = merged_ebv_cd8,
  df_all = df_all,
  cfg = config
)

saveRDS(
